ervices including cleaning/plumbing/electrical"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Upfront fixed pricing estimates during booking (specific ZAR not publicly listed)","features":""}]$json$::jsonb, $json${"google_play":"N/A (5K+ downloads, rating not extractable)","ios":"N/A (few reviews, mixed)"}$json$::jsonb, $json$["rigorous provider vetting","transparency focus","positive growth/news 2025","safety features","empowers informal sector"]$json$::jsonb, $json$["low visibility reviews","early-stage low adoption","occasional service no-shows"]$json$::jsonb, $json${"summary":"Limited; mostly promotional positive posts on LinkedIn/FB/Instagram, company claims high satisfaction, no major negative trends on HelloPeter or social.","positive_themes":["reliable pros","easy booking","safety","convenience","job creation"],"common_concerns":["limited reviews","low app downloads","isolated no-show complaints"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
