INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('sweepsouth', 'SweepSouth', 'home-cleaning', 80, 'GO', 'https://sweepsouth.com/wp-content/uploads/2024/09/Sweepsouth-logo-vertical-full-colour-tagline.png', 'https://www.sweepsouth.com', $json$[{"category":"Compliance","score":"18/20","description":"Pty Ltd registered; complies with CPA, ECT Act; underwritten insurance by authorized FSP Chubb; no major regulatory issues, lawsuits, or scams found in 2025/2026 searches; satisfaction guarantee and dispute processes in place."},{"category":"Customer Satisfaction","score":"18/25","description":"App ratings strong (GP 4.4/5 6.5K revs, iOS 4.7/5 522 revs); HelloPeter 3.49/5 (112 revs last 12mo, low NPS 21); mixed Google reviews with convenience praised but service inconsistencies noted."},{"category":"Product Value","score":"28/35","description":"Competitive tailored pricing with insurance/guarantee included; good value via convenience/vetting but some feel pricey vs private hires; express fixed rates accessible."},{"category":"Innovation","score":"9/10","description":"On-demand app bookings like Uber for cleaning; real-time notifications, recurring schedules, tailored quotes, SweepCred, MyHome Hub for private workers, 2025 expansions (office cleaning, dog walking, elder care); won SA Tech Challenge 2025 Digital Platforms."},{"category":"Customer Support","score":"11/15","description":"Channels: support@sweepsouth.com, WhatsApp, phone, in-app; responsive in app reviews but some complaints of delays/unresponsiveness in HelloPeter/Trustpilot."},{"category":"Accessibility & Security","score":"8/10","description":"Vetted SweepStars with background checks and 2+ years experience; insurance via Chubb; app data encrypted in transit; privacy policy implies POPIA compliance; no specific inclusivity mentions but app-based access."}]$json$::jsonb, $json$["vetted SweepStars","app bookings/notifications","indoor/outdoor cleaning","insurance coverage","satisfaction guarantee","recurring schedules","MyHome Hub"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Tailored quotes by home size/tasks; Express R199 Mon-Thu / R299 Fri-Sun","features":""}]$json$::jsonb, $json${"google_play":"4.4/5 (6.5K reviews)","ios":"4.7/5 (522 reviews)"}$json$::jsonb, $json$["convenient app platform","vetted reliable workers","strong insurance/safety","high app ratings","service variety","2025 tech award winner"]$json$::jsonb, $json$["cancellation policies","worker performance variability","occasional support delays"]$json$::jsonb, $json${"summary":"App/Google reviews mixed-positive (high ratings but service complaints); HelloPeter lower; recent news positive (tech award); minor gig worker concerns in 2024 reports.","positive_themes":["convenience","thorough cleaning","reliable replacements","friendly workers","user-friendly app","insurance peace of mind"],"common_concerns":["cancellation fees","inconsistent worker quality","app bugs","price increases","support delays"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
