 branches","proudly SA brand"]$json$::jsonb, $json$["scarce independent reviews","no public pricing","no app"]$json$::jsonb, $json${"summary":"Limited data; positive on own site, mixed HelloPeter (5-star happy, some complaints), no recent X posts.","positive_themes":["quality results","quick drying","professional staff","value pricing"],"common_concerns":["limited reviews data","mixed HelloPeter feedback"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
